"use strict";(globalThis.webpackChunklearncpp_docs=globalThis.webpackChunklearncpp_docs||[]).push([[5331],{85938(n,r,t){t.r(r),t.d(r,{assets:()=>c,contentTitle:()=>d,default:()=>i,frontMatter:()=>o,metadata:()=>e,toc:()=>p});const e=JSON.parse('{"id":"cpp20/template-lambdas","title":"\u6a21\u677f Lambda (Template Lambdas)","description":"C++20 \u6a21\u677f Lambda (Template Lambdas) \u6559\u5b66\u793a\u4f8b","source":"@site/docs/cpp20/09-template-lambdas.md","sourceDirName":"cpp20","slug":"/cpp20/09-template-lambdas","permalink":"/LearnModernCpp/docs/cpp20/09-template-lambdas","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"cpp20","permalink":"/LearnModernCpp/docs/tags/cpp-20"},{"inline":true,"label":"template_lambdas","permalink":"/LearnModernCpp/docs/tags/template-lambdas"}],"version":"current","sidebarPosition":10,"frontMatter":{"sidebar_position":10,"slug":"09-template-lambdas","title":"\u6a21\u677f Lambda (Template Lambdas)","description":"C++20 \u6a21\u677f Lambda (Template Lambdas) \u6559\u5b66\u793a\u4f8b","tags":["cpp20","template_lambdas"]},"sidebar":"docs","previous":{"title":"constinit","permalink":"/LearnModernCpp/docs/cpp20/08-constinit"},"next":{"title":"\u5706\u62ec\u53f7\u805a\u5408\u521d\u59cb\u5316 (Parenthesized Aggregate Initialization)","permalink":"/LearnModernCpp/docs/cpp20/10-aggregate-parens-init"}}');var a=t(74848),s=t(28453);const o={sidebar_position:10,slug:"09-template-lambdas",title:"\u6a21\u677f Lambda (Template Lambdas)",description:"C++20 \u6a21\u677f Lambda (Template Lambdas) \u6559\u5b66\u793a\u4f8b",tags:["cpp20","template_lambdas"]},d="\u6a21\u677f Lambda (Template Lambdas)",c={},p=[{value:"\u5b8c\u6574\u6e90\u7801",id:"\u5b8c\u6574\u6e90\u7801",level:2},{value:"\u53c2\u8003\u94fe\u63a5",id:"\u53c2\u8003\u94fe\u63a5",level:2}];function l(n){const r={a:"a",code:"code",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",pre:"pre",ul:"ul",...(0,s.R)(),...n.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(r.header,{children:(0,a.jsx)(r.h1,{id:"\u6a21\u677f-lambda-template-lambdas",children:"\u6a21\u677f Lambda (Template Lambdas)"})}),"\n",(0,a.jsx)(r.p,{children:"C++20 \u6807\u51c6\u5f15\u5165\u7684 \u6a21\u677f Lambda (Template Lambdas) \u7279\u6027\u5b8c\u6574\u6559\u5b66\u793a\u4f8b\u3002"}),"\n",(0,a.jsx)(r.h2,{id:"\u5b8c\u6574\u6e90\u7801",children:"\u5b8c\u6574\u6e90\u7801"}),"\n",(0,a.jsx)(r.pre,{children:(0,a.jsx)(r.code,{className:"language-cpp",metastring:'title="cpp20/09_template_lambdas.cpp"',children:'/**\r\n * ============================================================\r\n * \u7279\u6027\u540d\u79f0: \u6a21\u677f Lambda (Template Lambdas)\r\n * \u6240\u5c5e\u6807\u51c6: C++20\r\n * ============================================================\r\n *\r\n * [\u662f\u4ec0\u4e48]: C++20 \u5141\u8bb8 Lambda \u8868\u8fbe\u5f0f\u4f7f\u7528\u663e\u5f0f\u6a21\u677f\u53c2\u6570\u5217\u8868\uff0c\r\n *          \u8bed\u6cd5\u4e3a []<typename T>(T arg) {}\u3002\r\n *\r\n * [\u4e3a\u4ec0\u4e48\u5f15\u5165]: C++14 \u7684\u6cdb\u578b Lambda\uff08auto \u53c2\u6570\uff09\u65e0\u6cd5\u76f4\u63a5\u8bbf\u95ee\u7c7b\u578b\u53c2\u6570\uff0c\r\n *             \u6709\u4e9b\u573a\u666f\u9700\u8981\u663e\u5f0f\u6307\u5b9a\u6216\u7ea6\u675f\u7c7b\u578b\u53c2\u6570\uff0c\r\n *             \u5982\u5b8c\u7f8e\u8f6c\u53d1\u3001SFINAE\u3001concept \u7ea6\u675f\u7b49\u3002\r\n *\r\n * [\u5173\u952e\u8981\u70b9]:\r\n *   - \u8bed\u6cd5: []<typename T>(T arg) { ... }\r\n *   - \u53ef\u4ee5\u4f7f\u7528\u591a\u4e2a\u6a21\u677f\u53c2\u6570\u3001\u975e\u7c7b\u578b\u6a21\u677f\u53c2\u6570\r\n *   - \u652f\u6301 concept \u7ea6\u675f\r\n *   - \u4e0e auto \u53c2\u6570 Lambda \u5bf9\u6bd4\uff0c\u63d0\u4f9b\u4e86\u66f4\u591a\u7c7b\u578b\u63a7\u5236\u80fd\u529b\r\n * ============================================================\r\n */\r\n\r\n#include <concepts>\r\n#include <iostream>\r\n#include <string>\r\n#include <vector>\r\n#include <type_traits>\r\n#include <utility>\r\n#include <tuple>\r\n#include <array>\r\n\r\n// ===================== basic_usage() =====================\r\nvoid basic_usage() {\r\n    std::cout << "--- \u57fa\u7840\u7528\u6cd5 ---\\n\\n";\r\n\r\n    // C++14 \u6cdb\u578b Lambda\uff08auto \u53c2\u6570\uff09\r\n    auto generic_print_14 = [](const auto& value) {\r\n        std::cout << "[C++14 auto] \u503c: " << value << "\\n";\r\n    };\r\n\r\n    // C++20 \u6a21\u677f Lambda\uff08\u663e\u5f0f\u6a21\u677f\u53c2\u6570\uff09\r\n    auto generic_print_20 = []<typename T>(const T& value) {\r\n        std::cout << "[C++20 \u6a21\u677f] \u503c: " << value\r\n                  << " (\u7c7b\u578b\u5927\u5c0f: " << sizeof(T) << ")\\n";\r\n    };\r\n\r\n    generic_print_14(42);\r\n    generic_print_14(3.14);\r\n    generic_print_20(42);\r\n    generic_print_20(3.14);\r\n\r\n    // \u6a21\u677f Lambda \u53ef\u4ee5\u76f4\u63a5\u4f7f\u7528\u7c7b\u578b T\r\n    auto type_info = []<typename T>(T value) {\r\n        std::cout << "\u503c: " << value;\r\n        if constexpr (std::is_integral_v<T>) {\r\n            std::cout << " (\u6574\u6570\u7c7b\u578b)";\r\n        } else if constexpr (std::is_floating_point_v<T>) {\r\n            std::cout << " (\u6d6e\u70b9\u7c7b\u578b)";\r\n        } else {\r\n            std::cout << " (\u5176\u4ed6\u7c7b\u578b)";\r\n        }\r\n        std::cout << "\\n";\r\n    };\r\n\r\n    type_info(42);\r\n    type_info(3.14);\r\n    type_info(std::string("hello"));\r\n\r\n    // \u591a\u4e2a\u6a21\u677f\u53c2\u6570\r\n    auto pair_maker = []<typename T1, typename T2>(T1 a, T2 b) {\r\n        return std::pair<T1, T2>{a, b};\r\n    };\r\n\r\n    auto p = pair_maker(1, std::string("hello"));\r\n    std::cout << "\\npair: (" << p.first << ", " << p.second << ")\\n";\r\n}\r\n\r\n// ===================== advanced_usage() =====================\r\nvoid advanced_usage() {\r\n    std::cout << "\\n--- \u9ad8\u7ea7\u7528\u6cd5 ---\\n\\n";\r\n\r\n    // 1. concept \u7ea6\u675f\u7684\u6a21\u677f Lambda\r\n    auto add = []<std::integral T>(T a, T b) -> T {\r\n        return a + b;\r\n    };\r\n\r\n    std::cout << "-- concept \u7ea6\u675f --\\n";\r\n    std::cout << "add(3, 5) = " << add(3, 5) << "\\n";\r\n    // add(3.14, 2.71);  // \u7f16\u8bd1\u9519\u8bef\uff01\u4e0d\u6ee1\u8db3 std::integral\r\n\r\n    // 2. \u975e\u7c7b\u578b\u6a21\u677f\u53c2\u6570\r\n    auto make_array = []<typename T, std::size_t N>(T init_val) {\r\n        std::array<T, N> arr;\r\n        arr.fill(init_val);\r\n        return arr;\r\n    };\r\n\r\n    auto arr = make_array.template operator()<int, 5>(42);\r\n    std::cout << "\\n-- \u975e\u7c7b\u578b\u6a21\u677f\u53c2\u6570 --\\n";\r\n    std::cout << "array<int, 5> \u586b\u5145 42: ";\r\n    for (auto v : arr) std::cout << v << " ";\r\n    std::cout << "\\n";\r\n\r\n    // 3. \u5b8c\u7f8e\u8f6c\u53d1\r\n    auto forwarder = []<typename... Args>(Args&&... args) {\r\n        // \u5728 C++14 Lambda \u4e2d\u96be\u4ee5\u5b8c\u7f8e\u8f6c\u53d1\uff0c\u56e0\u4e3a\u4e0d\u77e5\u9053 auto&& \u7684\u539f\u59cb\u7c7b\u578b\r\n        // \u6a21\u677f Lambda \u53ef\u4ee5\u76f4\u63a5\u4f7f\u7528 Args \u8fdb\u884c\u8f6c\u53d1\r\n        return std::make_tuple(std::forward<Args>(args)...);\r\n    };\r\n\r\n    std::cout << "\\n-- \u5b8c\u7f8e\u8f6c\u53d1 --\\n";\r\n    std::string s = "lvalue";\r\n    auto t = forwarder(42, 3.14, s, std::string("rvalue"));\r\n    std::cout << "tuple: (" << std::get<0>(t) << ", " << std::get<1>(t)\r\n              << ", " << std::get<2>(t) << ", " << std::get<3>(t) << ")\\n";\r\n\r\n    // 4. \u4e0e auto \u53c2\u6570\u5bf9\u6bd4\uff1a\u8bbf\u95ee\u5bb9\u5668\u5143\u7d20\u7c7b\u578b\r\n    auto process_container = []<typename T>(const std::vector<T>& vec) {\r\n        // \u76f4\u63a5\u4f7f\u7528 T\uff0c\u4e0d\u9700\u8981 decltype(vec)::value_type\r\n        T sum{};\r\n        for (const auto& v : vec) {\r\n            sum += v;\r\n        }\r\n        std::cout << "\u5bb9\u5668\u5143\u7d20\u7c7b\u578b\u5927\u5c0f: " << sizeof(T)\r\n                  << ", \u5143\u7d20\u548c: " << sum << "\\n";\r\n    };\r\n\r\n    // \u5bf9\u6bd4 C++14 \u5199\u6cd5\uff1a\r\n    auto process_container_14 = [](const auto& vec) {\r\n        // \u9700\u8981\u7528 decltype \u6216 value_type \u83b7\u53d6\u5143\u7d20\u7c7b\u578b\r\n        using T = typename std::remove_reference_t<decltype(vec)>::value_type;\r\n        T sum{};\r\n        for (const auto& v : vec) {\r\n            sum += v;\r\n        }\r\n        std::cout << "\u5bb9\u5668\u5143\u7d20\u7c7b\u578b\u5927\u5c0f: " << sizeof(T)\r\n                  << ", \u5143\u7d20\u548c: " << sum << "\\n";\r\n    };\r\n\r\n    std::cout << "\\n-- \u8bbf\u95ee\u5bb9\u5668\u5143\u7d20\u7c7b\u578b --\\n";\r\n    std::vector<int> vi = {1, 2, 3, 4, 5};\r\n    std::vector<double> vd = {1.1, 2.2, 3.3};\r\n\r\n    std::cout << "[C++20 \u6a21\u677fLambda] ";\r\n    process_container(vi);\r\n    std::cout << "[C++14 auto Lambda] ";\r\n    process_container_14(vd);\r\n\r\n    // 5. \u9012\u5f52\u6a21\u677f Lambda\r\n    std::cout << "\\n-- \u9012\u5f52\u6a21\u677f Lambda --\\n";\r\n    auto print_all = []<typename T, typename... Rest>(\r\n        auto& self, const T& first, const Rest&... rest\r\n    ) -> void {\r\n        std::cout << first;\r\n        if constexpr (sizeof...(rest) > 0) {\r\n            std::cout << ", ";\r\n            self(self, rest...);\r\n        }\r\n    };\r\n\r\n    std::cout << "\u6253\u5370\u6240\u6709\u53c2\u6570: ";\r\n    print_all(print_all, 1, 2.5, "hello", \'A\');\r\n    std::cout << "\\n";\r\n}\r\n\r\n// ===================== pitfalls() =====================\r\nvoid pitfalls() {\r\n    std::cout << "\\n--- \u6613\u9519\u70b9 ---\\n\\n";\r\n\r\n    // \u9677\u96311\uff1a\u663e\u5f0f\u6307\u5b9a\u6a21\u677f\u53c2\u6570\u7684\u8bed\u6cd5\r\n    std::cout << "1. \u663e\u5f0f\u6307\u5b9a Lambda \u6a21\u677f\u53c2\u6570\u9700\u8981 .template operator()<>:\\n";\r\n    auto convert = []<typename To, typename From>(From val) -> To {\r\n        return static_cast<To>(val);\r\n    };\r\n    // \u8c03\u7528\u65b9\u5f0f\uff08\u7565\u663e\u7b28\u91cd\uff09\uff1a\r\n    double result = convert.template operator()<double, int>(42);\r\n    std::cout << "   convert<double>(42) = " << result << "\\n";\r\n    std::cout << "   \u8bed\u6cd5: lambda.template operator()<To, From>(arg)\\n\\n";\r\n\r\n    // \u9677\u96312\uff1aauto \u53c2\u6570\u548c\u6a21\u677f\u53c2\u6570\u53ef\u4ee5\u6df7\u7528\r\n    std::cout << "2. auto \u53c2\u6570\u548c\u663e\u5f0f\u6a21\u677f\u53c2\u6570\u53ef\u4ee5\u6df7\u7528:\\n";\r\n    auto mixed = []<typename T>(T a, auto b) {\r\n        std::cout << "   T = " << sizeof(T) << " \u5b57\u8282, auto = " << sizeof(b) << " \u5b57\u8282\\n";\r\n    };\r\n    mixed(42, 3.14);\r\n    std::cout << "   \u4f46\u8981\u6ce8\u610f\u5b83\u4eec\u662f\u72ec\u7acb\u7684\u6a21\u677f\u53c2\u6570\\n\\n";\r\n\r\n    // \u9677\u96313\uff1a\u6a21\u677f Lambda \u7684\u6355\u83b7\r\n    std::cout << "3. \u6a21\u677f Lambda \u4ecd\u7136\u53ef\u4ee5\u4f7f\u7528\u6355\u83b7:\\n";\r\n    int x = 10;\r\n    auto capture_and_template = [x]<typename T>(T val) {\r\n        std::cout << "   \u6355\u83b7\u7684 x = " << x << ", \u53c2\u6570 = " << val << "\\n";\r\n    };\r\n    capture_and_template(42);\r\n    capture_and_template(std::string("hello"));\r\n\r\n    // \u9677\u96314\uff1aC++14 auto Lambda \u4e2d\u5b8c\u7f8e\u8f6c\u53d1\u7684\u56f0\u96be\r\n    std::cout << "\\n4. C++14 Lambda \u5b8c\u7f8e\u8f6c\u53d1\u95ee\u9898:\\n";\r\n    std::cout << "   auto f = [](auto&& arg) {\\n";\r\n    std::cout << "       // decltype(arg) \u5305\u542b\u5f15\u7528\u4fe1\u606f\uff0c\u4e0d\u76f4\u89c2\\n";\r\n    std::cout << "       foo(std::forward<decltype(arg)>(arg));\\n";\r\n    std::cout << "   };\\n";\r\n    std::cout << "   C++20 \u6a21\u677f Lambda \u66f4\u76f4\u89c2:\\n";\r\n    std::cout << "   auto f = []<typename T>(T&& arg) {\\n";\r\n    std::cout << "       foo(std::forward<T>(arg));\\n";\r\n    std::cout << "   };\\n";\r\n}\r\n\r\n// ===================== main() =====================\r\nint main() {\r\n    std::cout << "===== \u6a21\u677f Lambda - C++20 =====\\n\\n";\r\n\r\n    basic_usage();\r\n    advanced_usage();\r\n    pitfalls();\r\n\r\n    return 0;\r\n}\n'})}),"\n",(0,a.jsx)(r.h2,{id:"\u53c2\u8003\u94fe\u63a5",children:"\u53c2\u8003\u94fe\u63a5"}),"\n",(0,a.jsxs)(r.ul,{children:["\n",(0,a.jsx)(r.li,{children:(0,a.jsx)(r.a,{href:"https://en.cppreference.com/w/cpp/language/lambda",children:"cppreference: \u6a21\u677f Lambda (Template Lambdas)"})}),"\n"]})]})}function i(n={}){const{wrapper:r}={...(0,s.R)(),...n.components};return r?(0,a.jsx)(r,{...n,children:(0,a.jsx)(l,{...n})}):l(n)}},28453(n,r,t){t.d(r,{R:()=>o,x:()=>d});var e=t(96540);const a={},s=e.createContext(a);function o(n){const r=e.useContext(s);return e.useMemo(function(){return"function"==typeof n?n(r):{...r,...n}},[r,n])}function d(n){let r;return r=n.disableParentContext?"function"==typeof n.components?n.components(a):n.components||a:o(n.components),e.createElement(s.Provider,{value:r},n.children)}}}]);